#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <map>
#include <sstream>

// Simple JSON parser (for learning purposes)
class SimpleJSON {
private:
    std::map<std::string, std::string> data;

    std::string trim(const std::string& str) {
        size_t start = str.find_first_not_of(" \t\n\r");
        size_t end = str.find_last_not_of(" \t\n\r");
        if (start == std::string::npos) return "";
        return str.substr(start, end - start + 1);
    }

    std::string unquote(const std::string& str) {
        if (str.size() >= 2 && str.front() == '"' && str.back() == '"') {
            return str.substr(1, str.size() - 2);
        }
        return str;
    }

public:
    bool parse(const std::string& json) {
        std::stringstream ss(json);
        std::string line;

        // Find opening brace
        while (std::getline(ss, line)) {
            if (line.find('{') != std::string::npos) break;
        }

        // Parse key-value pairs
        while (std::getline(ss, line)) {
            line = trim(line);
            if (line.find('}') != std::string::npos) break;
            if (line.empty()) continue;

            size_t colonPos = line.find(':');
            if (colonPos == std::string::npos) continue;

            std::string key = trim(line.substr(0, colonPos));
            std::string value = trim(line.substr(colonPos + 1));

            // Remove trailing comma
            if (value.back() == ',') value.pop_back();

            key = unquote(key);
            value = unquote(value);

            data[key] = value;
        }

        return true;
    }

    std::string getString(const std::string& key, const std::string& defaultVal = "") const {
        auto it = data.find(key);
        if (it != data.end()) return it->second;
        return defaultVal;
    }

    int getInt(const std::string& key, int defaultVal = 0) const {
        auto it = data.find(key);
        if (it != data.end()) {
            try {
                return std::stoi(it->second);
            } catch (...) {
                return defaultVal;
            }
        }
        return defaultVal;
    }

    double getDouble(const std::string& key, double defaultVal = 0.0) const {
        auto it = data.find(key);
        if (it != data.end()) {
            try {
                return std::stod(it->second);
            } catch (...) {
                return defaultVal;
            }
        }
        return defaultVal;
    }

    bool getBool(const std::string& key, bool defaultVal = false) const {
        auto it = data.find(key);
        if (it != data.end()) {
            if (it->second == "true") return true;
            if (it->second == "false") return false;
        }
        return defaultVal;
    }

    void print() const {
        std::cout << "{" << std::endl;
        for (auto it = data.begin(); it != data.end(); ++it) {
            std::cout << "  \"" << it->first << "\": \"" << it->second << "\"";
            if (std::next(it) != data.end()) std::cout << ",";
            std::cout << std::endl;
        }
        std::cout << "}" << std::endl;
    }
};

int main() {
    std::cout << "=== JSON-style Manual Parsing ===" << std::endl;

    // 1. Simple JSON string
    std::string json = R"(
    {
        "name": "Hero",
        "health": 100,
        "attack": 20,
        "defense": 15,
        "level": 5,
        "alive": true,
        "score": 1234.5
    }
    )";

    std::cout << "\n--- Parsing JSON ---" << std::endl;
    SimpleJSON parser;
    parser.parse(json);
    parser.print();

    // 2. Accessing data
    std::cout << "\n--- Accessing Data ---" << std::endl;
    std::cout << "Name: " << parser.getString("name") << std::endl;
    std::cout << "Health: " << parser.getInt("health") << std::endl;
    std::cout << "Attack: " << parser.getInt("attack") << std::endl;
    std::cout << "Defense: " << parser.getInt("defense") << std::endl;
    std::cout << "Level: " << parser.getInt("level") << std::endl;
    std::cout << "Alive: " << parser.getBool("alive") << std::endl;
    std::cout << "Score: " << parser.getDouble("score") << std::endl;

    // 3. Missing key handling
    std::cout << "\n--- Missing Key Handling ---" << std::endl;
    std::cout << "Mana: " << parser.getInt("mana", 50) << std::endl;
    std::cout << "Missing string: '" << parser.getString("missing", "default") << "'" << std::endl;

    // 4. Reading JSON from a file
    std::cout << "\n--- Reading from File ---" << std::endl;
    std::ifstream file("player.json");
    if (file.is_open()) {
        std::string fileContent, line;
        while (std::getline(file, line)) {
            fileContent += line + "\n";
        }
        file.close();

        SimpleJSON fileParser;
        fileParser.parse(fileContent);
        std::cout << "Loaded from file:" << std::endl;
        std::cout << "Name: " << fileParser.getString("name") << std::endl;
        std::cout << "Health: " << fileParser.getInt("health") << std::endl;
    } else {
        std::cout << "Creating sample player.json..." << std::endl;
        std::ofstream out("player.json");
        if (out.is_open()) {
            out << "{\n";
            out << "  \"name\": \"Hero\",\n";
            out << "  \"health\": 100,\n";
            out << "  \"attack\": 20,\n";
            out << "  \"defense\": 15,\n";
            out << "  \"level\": 5,\n";
            out << "  \"alive\": true\n";
            out << "}\n";
            out.close();
        }
    }

    std::cout << "\n--- Simple JSON Parser Features ---" << std::endl;
    std::cout << "✅ String, integer, double, bool support" << std::endl;
    std::cout << "✅ Default values for missing keys" << std::endl;
    std::cout << "✅ File reading support" << std::endl;
    std::cout << "❌ No nested objects support" << std::endl;

    return 0;
}

