#include <iostream>
#include <string>

// Simple JSON-like parser (for one object)
struct SimpleParser {
    std::string json;

    SimpleParser(const std::string& j) : json(j) {}

    std::string getString(const std::string& key) {
        std::string search = "\"" + key + "\":";
        size_t start = json.find(search);
        if (start == std::string::npos) return "";

        start = json.find('"', start + search.length());
        if (start == std::string::npos) return "";
        start++;

        size_t end = json.find('"', start);
        if (end == std::string::npos) return "";

        return json.substr(start, end - start);
    }

    int getInt(const std::string& key) {
        std::string search = "\"" + key + "\":";
        size_t start = json.find(search);
        if (start == std::string::npos) return 0;

        start = json.find(':', start);
        if (start == std::string::npos) return 0;
        start++;

        while (start < json.length() && (json[start] == ' ' || json[start] == '\t')) start++;

        size_t end = json.find_first_of(",}", start);
        if (end == std::string::npos) end = json.length();

        std::string value = json.substr(start, end - start);
        return std::stoi(value);
    }
};

int main() {
    std::cout << "=== Manual JSON Parsing ===" << std::endl;

    std::string playerJSON = R"({"name": "Hero", "health": 100, "attack": 20, "defense": 15, "level": 5})";
    std::cout << "Parsing: " << playerJSON << std::endl;

    SimpleParser player(playerJSON);

    std::cout << "\n--- Player Data ---" << std::endl;
    std::cout << "Name: " << player.getString("name") << std::endl;
    std::cout << "Health: " << player.getInt("health") << std::endl;
    std::cout << "Attack: " << player.getInt("attack") << std::endl;
    std::cout << "Defense: " << player.getInt("defense") << std::endl;
    std::cout << "Level: " << player.getInt("level") << std::endl;

    std::string enemyJSON = R"({"name": "Goblin", "health": 30, "attack": 8})";
    std::cout << "\nParsing: " << enemyJSON << std::endl;

    SimpleParser enemy(enemyJSON);

    std::cout << "\n--- Enemy Data ---" << std::endl;
    std::cout << "Name: " << enemy.getString("name") << std::endl;
    std::cout << "Health: " << enemy.getInt("health") << std::endl;
    std::cout << "Attack: " << enemy.getInt("attack") << std::endl;

    std::cout << "\n✅ Manual parsing complete!" << std::endl;

    return 0;
}
